 /// <summary>
 ///  Freezes the form fields by updating the design when the data source is activated.
 /// </summary>
public int active()
 {
     int ret = next active();

     FormRun formRun = this.formRun();

     Args args = formRun.args();
     if (args && args.caller() && args.caller().name() == formStr(LogisticsPostalAddressGrid))
     {
         ETGDMSIntegrationFormDesignHelper::updateDesignDMS(this);

         if(ETGACFParameters::find().EnableDMSIntegration == NoYes::Yes)
         {
             FormStringControl LogisticsPostalAddress_CountryRegionId = formRun.control(formRun.controlId("LogisticsPostalAddress_CountryRegionId")) as FormStringControl;
             FormStringControl Roles = formRun.control(formRun.controlId("Roles")) as FormStringControl;

             if (LogisticsPostalAddress_CountryRegionId)
             {
                 LogisticsPostalAddress_CountryRegionId.enabled(false);
             }
             else
             {
                 LogisticsPostalAddress_CountryRegionId.enabled(true);
             }
             if(Roles)
             {
                 Roles.enabled(false);

             }
             else
             {
                 Roles.enabled(true);

             }

         }
     }

     return ret;
 }

